appendOnce('server/test/facility-groups.test.js', 'target production completion disables the run switch', "\ntest('target production completion disables the run switch', () => {\n  const world = createWorld(now);\n  const player = ensurePlayer(world, alice, now);\n  player.credits = 100;\n  player.facilityGroups = [group('farm', 1, {\n    enabled: true,\n    status: 'running',\n    participatingCount: 1,\n    cycleStartedAt: now,\n    productionMode: 'target',\n    targetQuantity: 2,\n    completedQuantity: 0,\n  })];\n  migrateFacilityGroupWorld(world, now);\n\n  processFacilityGroupWorld(world, now + 30_000);\n\n  const completed = player.facilityGroups[0];\n  assert.equal(player.inventories.grain.available, 2);\n  assert.equal(completed.productionMode, 'target');\n  assert.equal(completed.completedQuantity, 2);\n  assert.equal(completed.enabled, false);\n  assert.equal(completed.status, 'stopped');\n  assert.equal(completed.statusReason, 'plan_complete');\n  assert.equal(completed.participatingCount, 0);\n  assert.equal(completed.pendingJoinCount, 0);\n  assert.equal(completed.cycleStartedAt, undefined);\n});\n\ntest('target completion preserves pending plan but still stops', () => {\n  const world = createWorld(now);\n  const player = ensurePlayer(world, alice, now);\n  player.credits = 100;\n  player.facilityGroups = [group('farm', 1, {\n    enabled: true,\n    status: 'running',\n    participatingCount: 1,\n    cycleStartedAt: now,\n    productionMode: 'target',\n    targetQuantity: 2,\n    completedQuantity: 0,\n    pendingProductionPlan: {\n      mode: 'continuous',\n      requestedAt: now + 1,\n    },\n  })];\n  migrateFacilityGroupWorld(world, now);\n\n  processFacilityGroupWorld(world, now + 30_000);\n\n  const completed = player.facilityGroups[0];\n  assert.equal(completed.productionMode, 'continuous');\n  assert.equal(completed.pendingProductionPlan, undefined);\n  assert.equal(completed.enabled, false);\n  assert.equal(completed.status, 'stopped');\n  assert.equal(completed.statusReason, 'plan_complete');\n});\n");
appendOnce('src/styles/industry-system.css', 'Production management layout v3', "\n/* Production management layout v3: sticky build column and fixed-height factory cards. */\n.production-grid {\n  grid-template-columns: minmax(280px, 320px) minmax(0, 1fr);\n  align-items: start;\n}\n\n.production-build-card {\n  position: sticky;\n  top: var(--space-3);\n  align-self: start;\n  display: grid;\n  grid-template-columns: 1fr;\n  align-items: start;\n  gap: var(--space-3);\n  max-height: calc(100dvh - var(--space-6));\n  overflow-y: auto;\n  overscroll-behavior: contain;\n}\n\n.production-build-card .widget-heading,\n.production-build-card .ui-data-list,\n.production-build-card > .ui-helper-text {\n  grid-column: auto;\n}\n\n.production-build-card .ui-data-list {\n  display: grid;\n  grid-template-columns: 1fr;\n  gap: 0;\n}\n\n.facility-status-header {\n  position: relative;\n  align-items: flex-start;\n}\n\n.facility-status-header > .ui-switch {\n  flex: 0 0 auto;\n  align-self: flex-start;\n  margin-left: auto;\n}\n\n.facility-status-copy {\n  min-width: 0;\n  display: grid;\n  gap: var(--space-1);\n}\n\n.facility-count-summary {\n  display: flex;\n  align-items: center;\n  flex-wrap: wrap;\n  gap: var(--space-1) var(--space-3);\n  color: var(--color-text-muted);\n  font-size: var(--font-size-xs);\n}\n\n.facility-count-summary span {\n  white-space: nowrap;\n}\n\n.facility-count-summary strong {\n  color: var(--color-text-primary);\n  font-size: var(--font-size-sm);\n}\n\n.production-plan-card {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) minmax(260px, 1.35fr);\n  align-items: center;\n  gap: var(--space-2);\n}\n\n.production-plan-summary {\n  min-width: 0;\n  display: grid;\n  gap: 0.1rem;\n}\n\n.production-plan-summary strong,\n.production-plan-summary small {\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.production-plan-summary strong {\n  font-size: var(--font-size-sm);\n}\n\n.production-plan-summary small {\n  color: var(--color-text-muted);\n  font-size: var(--font-size-xs);\n}\n\n.production-plan-controls {\n  display: grid;\n  grid-template-columns: minmax(120px, 1fr) minmax(100px, 0.8fr) auto;\n  align-items: center;\n  gap: var(--space-2);\n}\n\n.facility-market-link-row {\n  align-self: end;\n}\n\n@media (min-width: 1381px) {\n  .facility-group-list {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n    align-items: start;\n  }\n}\n\n@media (min-width: 961px) and (max-width: 1380px) {\n  .facility-group-list {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (min-width: 961px) {\n  .facility-group-card {\n    height: 384px;\n    min-height: 384px;\n    max-height: 384px;\n    grid-template-rows: auto auto minmax(40px, auto) minmax(0, 1fr) auto;\n    overflow: hidden;\n  }\n}\n\n@media (max-width: 960px) {\n  .production-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .production-build-card {\n    position: static;\n    top: auto;\n    max-height: none;\n    overflow: visible;\n  }\n\n  .facility-group-card {\n    height: auto;\n    min-height: 0;\n    max-height: none;\n    overflow: visible;\n  }\n\n  .production-plan-card {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 720px) {\n  .facility-count-summary {\n    align-items: flex-start;\n    flex-direction: column;\n    gap: var(--space-1);\n  }\n\n  .production-plan-controls {\n    grid-template-columns: 1fr;\n  }\n\n  .production-plan-controls .ui-button {\n    width: 100%;\n  }\n}\n");

const docs = {"README.md": "\n## 生产与仓库布局 V3\n\n- 建设新工厂卡在桌面生产管理区独占左侧列并使用 `sticky` 常驻；移动端恢复普通文档流。\n- 工厂卡桌面固定高度，开关固定在右上角；异常原因直接合并为“异常：仓库已满／资金不足／原料不足”等顶部状态。\n- 工厂数量只在标题和顶部摘要展示“运行中／下一周期加入／冻结中”，不再显示持有卡片或下一周期产量说明。\n- 生产计划使用“当前计划 + 下拉框 + 可选数量输入 + 保存计划”的单行结构；定量生产完成后服务器关闭运行开关。\n- 共享仓库允许无限扩容，当前等级升级容量增量为 `250 + 50 × (等级 - 1)`，升级费用保持 `150 × 等级²`。\n- 客户端状态版本为 11，世界状态版本为 7。\n", "docs/WAREHOUSE_EXPANSION_DESIGN.md": "\n## V3：无限扩容与递增容量（2026-07-12）\n\n仓库不再存在玩家可见最高等级。等级标题只显示“等级 N”，不得显示 `/12`、满级、最高容量或已达最高等级。\n\n当前等级升级至下一等级的容量增量为：\n\n```text\n250 + 50 × (当前等级 - 1)\n```\n\n等级 1 至 6 的总容量依次为 500、750、1050、1400、1800、2250。升级费用继续使用 `150 × 当前等级²`。服务器必须保留旧容量不下降，并拒绝非安全整数或溢出结果。\n\n客户端状态版本升级为 11，新增 `warehouseNextCapacityIncrease`，移除 `warehouseMaxLevel`。世界状态版本升级为 7。工厂因仓库已满进入异常后，扩容完成仍由统一协调函数自动恢复，不补算异常期间周期。\n", "docs/WAREHOUSE_AND_FACTORY_CARD_LAYOUT_DESIGN.md": "\n## V3：左侧常驻建设卡、固定工厂卡与无限仓库（2026-07-12）\n\n- 建设新工厂卡独占生产管理区左侧列，桌面使用 `position: sticky`，移动端恢复 `position: static`。\n- 工厂卡桌面固定高度 384px，移动端自然高度；开关始终对齐右上角。\n- 运行状态不显示“正常生产中”说明；剩余周期只在进度区出现。\n- 异常原因直接合并为“异常：仓库已满”“异常：资金不足”“异常：原料不足”等顶部状态。\n- 标题显示总数量；正文只在顶部摘要显示“运行中／下一周期加入／冻结中”，不得恢复独立数量卡片。\n- 删除“下一周期按若干座结算”说明。\n- 计划区只保留当前计划、模式下拉框、定量输入和“保存计划”按钮，不得恢复持续／定量状态小卡片。\n- 定量生产完成后关闭开关；若存在待生效计划，先保存为新当前计划，但仍保持停止，等待玩家再次开启。\n- 仓库无限扩容，每级容量增量随等级增加，等级标题不得出现最高等级。\n", "docs/FACILITY_GROUP_AND_MARKET_V3_DESIGN.md": "\n## 定量完成关停补充规则（2026-07-12）\n\n定量计划达到目标后必须调用统一停止流程：`enabled = false`、`status = stopped`、`statusReason = plan_complete`，并清除运行周期。存在 `pendingProductionPlan` 时先将其提升为当前计划，再关闭开关；不得自动继续下一周期。\n", "docs/INDUSTRY_AND_PRODUCTION_DESIGN.md": "\n## 生产卡 V3 规则（2026-07-12）\n\n工厂仍使用运行、停止、异常三种顶层状态和自动恢复机制。异常原因合并到顶部状态标签；运行周期剩余时间只在进度区显示。卡片桌面固定高度 384px，数量摘要使用“运行中／下一周期加入／冻结中”，开关固定右上角。\n\n运行中修改计划仍在下一周期应用，但定量生产完成后关闭开关。存在待生效计划时保留并应用为新当前计划，工厂仍以“停止：计划完成”结束。\n", "docs/PAGE_CONTENT_AND_NAVIGATION_DESIGN.md": "\n## 生产页布局 V3（2026-07-12）\n\n共享仓库继续位于生产管理区之前。建设新工厂卡独占左侧列并在桌面滚动时常驻，工厂集群位于右侧；不超过 960px 时恢复上下布局。工厂卡固定高度规则只适用于桌面。\n\n工厂卡不得恢复运行描述、独立持有卡、下一周期产量辅助句或持续／定量状态小卡片。异常原因、运行数量摘要和开关都归属顶部区域。\n", "docs/UI_DESIGN_SYSTEM.md": "\n## 工厂卡桌面固定高度与控件规则（2026-07-12）\n\n工厂卡桌面固定高度为 384px，移动端使用自然高度。开关继续使用唯一 `SwitchControl`／`.ui-switch`，并固定在卡片右上角。异常原因必须写入状态标签，不得通过开关变体表达。\n\n计划编辑采用同一行的摘要、下拉框、可选数字输入和统一“保存计划”按钮，不得新增“持续”“定量”状态小卡片或另一套开关样式。\n"};
for (const [path, content] of Object.entries(docs)) {
  appendOnce(path, content.trim().split('\n')[0].replace(/^#+\s*/, ''), content);
}
